package com.sme.erp.accounting.service.impl;
import com.sme.erp.accounting.dto.*; import com.sme.erp.accounting.entity.Account; import com.sme.erp.accounting.enums.AccountType; import com.sme.erp.accounting.repository.*; import com.sme.erp.accounting.service.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.math.*; import java.time.*; import java.time.format.TextStyle; import java.util.*;
@Service public class FinancialDashboardServiceImpl implements FinancialDashboardService {private final AccountRepository accounts;private final JournalEntryLineRepository lines;private final AccountingReportService reports;private final BudgetService budgets;public FinancialDashboardServiceImpl(AccountRepository a,JournalEntryLineRepository l,AccountingReportService r,BudgetService b){accounts=a;lines=l;reports=r;budgets=b;}
 @Transactional(readOnly=true) public FinancialDashboardDTO get(Integer year){int y=year==null?LocalDate.now().getYear():year;LocalDate f=LocalDate.of(y,1,1),t=LocalDate.of(y,12,31);ProfitLossDTO pl=reports.getProfitLoss(f,t);TrialBalanceDTO tb=reports.getTrialBalance(null,t);BudgetActualDTO ba=budgets.actual(y,f,t,null,null);List<Account> allAccounts=accounts.findAll();List<FinancialDashboardDTO.ChartPointDTO> monthly=new ArrayList<>(),trend=new ArrayList<>(),expense=new ArrayList<>();for(int m=1;m<=12;m++){LocalDate mf=LocalDate.of(y,m,1),mt=mf.withDayOfMonth(mf.lengthOfMonth());BigDecimal inc=BigDecimal.ZERO,ex=BigDecimal.ZERO;for(Account a:allAccounts){BigDecimal d=safe(lines.sumDebit(a.getId(),mf,mt)),c=safe(lines.sumCredit(a.getId(),mf,mt));if(a.getAccountType()==AccountType.INCOME)inc=inc.add(c.subtract(d));if(a.getAccountType()==AccountType.EXPENSE)ex=ex.add(d.subtract(c));}String label=mf.getMonth().getDisplayName(TextStyle.SHORT,Locale.ENGLISH);monthly.add(new FinancialDashboardDTO.ChartPointDTO(label,inc,ex));trend.add(new FinancialDashboardDTO.ChartPointDTO(label,balance(mt,"1000","Cash"),balance(mt,"1010","Bank")));}for(var e:pl.expenses())expense.add(new FinancialDashboardDTO.ChartPointDTO(e.groupName()+" - "+e.accountName(),e.amount(),BigDecimal.ZERO));List<FinancialDashboardDTO.ChartPointDTO> bva=ba.rows().stream().map(r->new FinancialDashboardDTO.ChartPointDTO(r.accountName()+" / "+r.costCenterName(),r.budgetAmount(),r.actualAmount())).toList();return new FinancialDashboardDTO(balance(t,"1000","Cash"),balance(t,"1010","Bank"),balance(t,"1020","Accounts Receivable"),balanceCredit(t,"2000","Accounts Payable"),pl.netProfitLoss(),pl.totalExpense(),ba.utilizationPercentage(),tb.getDifferenceAmount(),monthly,trend,expense,bva);}
 private BigDecimal balance(LocalDate t,String code,String name){return resolveAccount(code,name).map(a->safe(lines.sumDebit(a.getId(),null,t)).subtract(safe(lines.sumCredit(a.getId(),null,t)))).orElse(BigDecimal.ZERO);}private BigDecimal balanceCredit(LocalDate t,String code,String name){return balance(t,code,name).negate();}private Optional<Account> resolveAccount(String code,String name){Optional<Account> byCode=accounts.findByAccountCodeIgnoreCase(code);return byCode.isPresent()?byCode:accounts.findByAccountNameIgnoreCase(name);}private BigDecimal safe(BigDecimal v){return v==null?BigDecimal.ZERO:v;}
}
